module timer_core #(
    parameter integer DATA_WIDTH = 32
) (
    input  logic                  pclk,
    input  logic                  presetn,
    input  logic [DATA_WIDTH-1:0] load_q,
    input  logic                  enable_q,
    output logic [DATA_WIDTH-1:0] count_q,
    output logic                  irq
);
    // Conceptual timer_control FSM states from SSOT fsm.timer_control.
    localparam [1:0] DISABLED      = 2'd0;
    localparam [1:0] ENABLED_COUNT = 2'd1;
    localparam [1:0] RELOAD_IRQ    = 2'd2;

    logic [1:0] state_q;
    logic [1:0] state_d;
    logic [DATA_WIDTH-1:0] count_d;
    logic irq_d;

    wire count_is_zero;
    wire enabled_count_nonzero;
    wire timer_zero_event;

    assign count_is_zero = (count_q == {DATA_WIDTH{1'b0}});
    assign enabled_count_nonzero = enable_q & (~count_is_zero);
    // TIMER_ZERO interrupt source: enabled zero tick reloads LOAD and pulses irq for one pclk.
    assign timer_zero_event = enable_q & count_is_zero;

    // Next-state logic mirrors the SSOT DISABLED, ENABLED_COUNT, and RELOAD_IRQ transitions.
    always @(*) begin
        state_d = state_q;
        case (state_q)
            DISABLED: begin
                if (enable_q) begin
                    state_d = ENABLED_COUNT;
                end else begin
                    state_d = DISABLED;
                end
            end
            ENABLED_COUNT: begin
                if (!enable_q) begin
                    state_d = DISABLED;
                end else if (count_is_zero) begin
                    state_d = RELOAD_IRQ;
                end else begin
                    state_d = ENABLED_COUNT;
                end
            end
            RELOAD_IRQ: begin
                if (!enable_q) begin
                    state_d = DISABLED;
                end else begin
                    state_d = ENABLED_COUNT;
                end
            end
            default: begin
                state_d = DISABLED;
            end
        endcase
    end

    // Datapath implements FunctionalModel.apply tick transactions at the module boundary:
    // disabled hold, enabled decrement, and enabled zero reload/irq pulse.
    always @(*) begin
        count_d = count_q;
        irq_d = 1'b0;
        if (enable_q) begin
            if (enabled_count_nonzero) begin
                count_d = count_q - {{(DATA_WIDTH-1){1'b0}}, 1'b1};
                irq_d = 1'b0;
            end else begin
                count_d = load_q;
                irq_d = 1'b1;
            end
        end else begin
            count_d = count_q;
            irq_d = 1'b0;
        end
    end

    // Active-low reset clears count_q and irq; each non-reset pclk performs one SSOT timer tick decision.
    always @(posedge pclk or negedge presetn) begin
        if (!presetn) begin
            state_q <= DISABLED;
            count_q <= {DATA_WIDTH{1'b0}};
            irq <= 1'b0;
        end else begin
            state_q <= state_d;
            count_q <= count_d;
            irq <= irq_d;
        end
    end
endmodule

